const { Client } = require('pg');
const bcrypt = require('bcryptjs');

async function createTestUser() {
  const client = new Client({ connectionString: 'postgresql://postgres:postgres@localhost:5432/appflota' });

  try {
    await client.connect();

    // Check if the users table exists
    const tableCheck = await client.query(`
      SELECT EXISTS (
        SELECT FROM information_schema.tables 
        WHERE table_schema = 'public' 
        AND table_name = 'users'
      );
    `);

    if (!tableCheck.rows[0].exists) {
      console.log("Error: La tabla 'users' no existe a├║n. Necesitas crear el esquema primero.");
      return;
    }

    const email = 'emartinez@complejoavante.com';
    const password = '1234';
    const hashedPassword = await bcrypt.hash(password, 10);

    // Get the driver role id
    let roleId;
    const roleQuery = await client.query("SELECT id FROM roles WHERE name = 'CONDUCTOR'");
    if (roleQuery.rows.length > 0) {
      roleId = roleQuery.rows[0].id;
    } else {
      console.log("Warning: Rol 'CONDUCTOR' no encontrado, usando null.");
    }

    // Insert or update the user
    const res = await client.query(`
      INSERT INTO users (first_name, last_name, email, password_hash, is_active)
      VALUES ('E.', 'Martinez', $1, $2, true)
      ON CONFLICT (email) DO UPDATE 
      SET password_hash = EXCLUDED.password_hash
      RETURNING id
    `, [email, hashedPassword]);

    const userId = res.rows[0].id;
    console.log(`Usuario creado exitosamente con ID: ${userId}`);

    // Insert role association if role exists
    if (roleId) {
      await client.query(`
        INSERT INTO user_roles (user_id, role_id)
        VALUES ($1, $2)
        ON CONFLICT DO NOTHING
      `, [userId, roleId]);
      console.log("Rol CONDUCTOR asignado exitosamente.");
    }

  } catch (err) {
    console.error('Error:', err.message);
  } finally {
    await client.end();
  }
}

createTestUser();
